// frontend/src/components/WeatherApp.jsx
import React, { useEffect, useState, useCallback } from "react";
import WeatherOverlay from "./WeatherOverlay";
import Radar from "./Radar";
import Forecast from "./Forecast";
import BottomBar from "./BottomBar";
import SearchSection from "./SearchSection";
import { getCurrentWeather, getForecast16 } from "../api/weather";

const DEFAULT_CITY = "Atlanta,US";

export default function WeatherApp() {
  const [location, setLocation] = useState(DEFAULT_CITY);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [summary, setSummary] = useState("");
  const [weather, setWeather] = useState({ current: {}, hourly: [], daily: [] });
  const [forecast16, setForecast16] = useState([]);

  const loadAll = useCallback(async (loc) => {
    setLoading(true);
    setError("");
    try {
      const { weather: w, summary: s } = await getCurrentWeather(loc);
      setWeather(w);
      setSummary(s ?? "");
      const f16 = await getForecast16(loc, 16);
      setForecast16(f16?.weather?.daily ?? []);
    } catch (e) {
      console.error(e);
      setError(e?.response?.data?.detail || e.message || "Failed to fetch weather.");
    } finally {
      setLoading(false);
    }
  }, []);

  // initial load
  useEffect(() => {
    loadAll(location);
  }, [loadAll, location]);

  // called by SearchSection
  const handleSearch = (locStr) => {
    if (!locStr) return;
    setLocation(locStr);
  };

  const now = weather?.current || {};
  const hourly = Array.isArray(weather?.hourly) ? weather.hourly : [];
  const daily = Array.isArray(weather?.daily) ? weather.daily : [];

  return (
    <div className="relative min-h-screen flex flex-col bg-white dark:bg-black text-gray-900 dark:text-gray-100">
      {/* Dynamic background / overlay */}
      <WeatherOverlay condition={now?.weather} />

      {/* Top search */}
      <div className="z-10">
        <SearchSection onSearch={handleSearch} defaultValue={location} loading={loading} />
      </div>

      {/* Status / summary */}
      <div className="z-10 mx-auto mt-4 w-full max-w-3xl px-4">
        {error ? (
          <div className="rounded-xl bg-red-500/10 border border-red-500/30 p-3 text-sm">
            {error}
          </div>
        ) : (
          <div className="rounded-2xl bg-black/30 backdrop-blur-md text-white p-4">
            <div className="text-lg font-semibold">Now in {location}</div>
            <div className="text-4xl font-bold mt-1">
              {now?.temp != null ? Math.round(now.temp) : "--"}°C
            </div>
            <div className="opacity-80">{now?.weather || "—"}</div>
            {summary && <div className="mt-3 opacity-90">{summary}</div>}
          </div>
        )}
      </div>

      {/* Radar */}
      <div className="z-10 mt-6 px-4">
        <div className="mx-auto w-full max-w-5xl">
          <Radar lat={undefined} lon={undefined} />
        </div>
      </div>

      {/* Forecast blocks */}
      <div className="z-10 mt-6 px-4 pb-24">
        <div className="mx-auto w-full max-w-3xl">
          <Forecast hourly={hourly} daily={daily} daily16={forecast16} />
        </div>
      </div>

      {/* Bottom bar */}
      <BottomBar active="home" />
    </div>
  );
}
